function makeId(title, company) {
  return 'j_' +
    (
      title.toLowerCase().replace(/[^a-z0-9]/g, '') +
      company.toLowerCase().replace(/[^a-z0-9]/g, '')
    ).slice(0, 16);
}

const body =
  $input.first().json.data ||
  $input.first().json.body ||
  '';

const now = new Date().toISOString();

const jobs = [];

const hrefs = [...body.matchAll(
  /<a class="job-title-href"[^>]*href="([^"]+)"[^>]*>(.*?)<\/a>/gi
)];

for (const m of hrefs) {

  const href = m[1];
  const title = m[2].replace(/<[^>]+>/g, '').trim();

  const start = Math.max(0, m.index - 500);
  const end = Math.min(body.length, m.index + 5000);

  const chunk = body.slice(start, end);

  const company =
    chunk.match(/<p class="company-name">\s*([^<]+)\s*</i)?.[1]?.trim() ||
    'Unknown';

  const location =
    chunk.match(/row-1-item locations[\s\S]*?<a[^>]*>([^<]+)<\/a>/i)?.[1]?.trim() ||
    'India';

  const stipend =
    chunk.match(/class=['"]stipend['"][^>]*>([^<]+)</i)?.[1]?.trim() ||
    null;

  const id = makeId(title, company);

  jobs.push({
    job_id: id,
    source: 'internshala',
    title,
    company,
    location,
    stipend,
    job_url: 'https://internshala.com' + href,
    job_type: 'internship',
    hash: id.slice(2),
    date_found: now,
    date_scraped: now,
    date_posted: now,
    description_text: '',
    skills_required: [],
    relevance_score: 0,
    status: 'new',
    tags: []
  });
}

return jobs.length
  ? jobs.map(j => ({ json: j }))
  : [{ json: { _sentinel: true, source: 'internshala' } }];

function makeId(title, company) {
  return 'j_' +
    (
