const now = new Date().toISOString();
const body = $input.first().json.body || '';

if (body.length < 100) {
  return [{ json: { _sentinel: true, source: 'remoteok' } }];
}

const jobs = [];

const jobRegex = /<tr[^>]*class="[^"]*job[^"]*"[^>]*data-slug="([^"]+)"[^>]*>([\s\S]*?)<\/tr>/gi;

let match;

while ((match = jobRegex.exec(body)) !== null) {
  const slug = match[1];
  const block = match[2];

  const title =
    (block.match(/itemprop="title"[^>]*>([^<]+)/i)?.[1] || '').trim();

  const company =
    (block.match(/itemprop="name"[^>]*>([^<]+)/i)?.[1] || '').trim();

  if (!title || !company) continue;

  const tags = [];
  const tagMatches = block.matchAll(/class="[^"]*tag[^"]*"[^>]*>([^<]+)/gi);

  for (const t of tagMatches) {
    tags.push(t[1].trim());
  }

  const id = makeId(title, company);

  jobs.push({
    job_id: id,
    source: 'remoteok',
    title,
    company,
    location: 'Remote',
    job_url: slug ? `https://remoteok.io/${slug}` : null,
    job_type: 'remote',
    hash: id.slice(2),
    date_found: now,
    date_scraped: now,
    date_posted: now,
    description_text: '',
    skills_required: tags,
    relevance_score: 0,
    status: 'new',
    tags: []
  });
}

if (!jobs.length) {
  return [{ json: { _sentinel: true, source: 'remoteok' } }];
}

return jobs.map(j => ({ json: j }));

function makeId(title, company) {
