    ).slice(0, 16);
}

const now = new Date().toISOString();
const body = $input.first().json.body || '';

if (body.length < 100) {
  return [{ json: { _sentinel: true, source: 'hn_jobs' } }];
}

const AI_RE = /\b(ai|ml|machine[\s-]?learning|nlp|llm|large language|deep learning|data sci|neural|computer vision|generative)\b/i;

const jobs = [];

const linkRegex = /<a[^>]*href="([^"]+)"[^>]*>(.*?)<\/a>/gi;

let match;

while ((match = linkRegex.exec(body)) !== null) {
  const href = match[1];
  const rawTitle = match[2].replace(/<[^>]+>/g, '').trim();

  if (!rawTitle) continue;
  if (!AI_RE.test(rawTitle)) continue;

  const parts = rawTitle.split(/\s*[\|\u2013\u2014]\s*/);

  const company =
    parts.length > 1
      ? parts[parts.length - 1].trim()
      : 'HN Listing';

  const cleanTitle = parts[0].trim();

  const id = makeId(cleanTitle, company);

  jobs.push({
    job_id: id,
    source: 'hn_jobs',
    title: cleanTitle,
    company,
    location: 'Remote',
    job_url: href.startsWith('http') ? href : null,
    job_type: 'full-time',
    hash: id.slice(2),
    date_found: now,
    date_scraped: now,
    date_posted: now,
    description_text: '',
    skills_required: [],
    relevance_score: 0,
    status: 'new',
    tags: []
  });
}

if (!jobs.length) {
  return [{ json: { _sentinel: true, source: 'hn_jobs' } }];
}

return jobs.map(j => ({ json: j }));

const all = $input.all();

const ghItem = all.find(
  i => i.json.sha !== undefined &&
       i.json.content !== undefined
);

const jobItems = all.filter(
  i => i.json.source !== undefined &&
       !i.json._sentinel
);

let existing = [];
let sha = null;

if (ghItem) {
  try {
    const db = JSON.parse(
      Buffer.from(
        ghItem.json.content,
        'base64'
      ).toString('utf8')
    );

    existing = db.jobs || [];
    sha = ghItem.json.sha || null;
  } catch {}
}

const seen = new Set(
  existing.map(j => j.hash)
);

const fresh = jobItems
  .map(i => i.json)
  .filter(j => j.hash && !seen.has(j.hash));

return [{
  json: {
    fresh_jobs: fresh,
    existing,
    sha,
    fresh_count: fresh.length
  }
}];

const d    = $input.first().json;
const jobs = (d.fresh_jobs || []).slice(0, 20);
const listing = jobs.map((j, i) =>
  (i + 1) + '. hash:' + j.hash + ' | "' + j.title + '" at ' + j.company +
  ' | ' + j.location + ' | ' + j.job_type
).join('\n');

return [{ json: {
  groq_request: {
    model: 'openai/gpt-oss-120b',
    temperature: 0.2, max_tokens: 700,
    messages: [
      { role: 'system',
        content: 'Score each job 0-100 for a B.Tech AI/ML grad with PyTorch, TensorFlow, NLP, Transformers, LLMs. Return ONLY a JSON array, no other text: [{"hash":"16_char_hash","score":number}]' },
      { role: 'user', content: 'Score these jobs:\n' + listing }
    ]
  },
  fresh_jobs: d.fresh_jobs,
  existing:   d.existing,
  sha:        d.sha
} }];

const all = $input.all();

const groqItem = all.find(i => i.json.choices !== undefined);

// Get original data directly from Build Groq Score Req
const data = $('Build Groq Score Req').first().json;

const fresh = data.fresh_jobs || [];
const existing = data.existing || [];
const sha = data.sha || null;

let scoreMap = {};

if (groqItem) {
  try {
    const raw = groqItem.json.choices[0].message.content;

    const clean = raw
      .replace(/```json/g, '')
      .replace(/```/g, '')
      .trim();

    JSON.parse(clean).forEach(s => {
      if (s.hash) {
        scoreMap[s.hash] = Math.min(
          100,
          Math.max(0, Number(s.score))
        );
      }
    });
  } catch (e) {}
}

const scored = fresh.map(j => {

  if (scoreMap[j.hash] !== undefined) {
    return {
      ...j,
      relevance_score: scoreMap[j.hash]
    };
  }

  const t = (j.title || '').toLowerCase();

  let s = 42;

  if (/\b(llm|large language model|generative ai|gen ai)\b/.test(t))
    s = 88;
  else if (/\b(nlp|natural language processing)\b/.test(t))
    s = 83;
  else if (/\b(machine learning engineer|ml engineer)\b/.test(t))
    s = 78;
  else if (/\b(ai engineer|artificial intelligence)\b/.test(t))
    s = 75;
  else if (/\b(deep learning|neural network)\b/.test(t))
    s = 72;
  else if (/\b(computer vision)\b/.test(t))
    s = 70;
  else if (/\b(data scientist|data science)\b/.test(t))
    s = 67;

  if (/intern/i.test(j.job_type || j.title || ''))
    s = Math.min(100, s + 8);

  if (/remote/i.test(j.location || ''))
    s = Math.min(100, s + 5);

  return {
    ...j,
    relevance_score: s
  };
});

const allRanked = scored.sort(
  (a, b) => b.relevance_score - a.relevance_score
);

const merged = [
  ...allRanked,
  ...existing
].slice(0, 2000);

const db = {
  metadata: {
    last_updated: new Date().toISOString(),
    total_jobs: merged.length,
    new_today: allRanked.length
  },
  jobs: merged
};

const payload = {
  message:
    'auto: job sync ' +
    new Date().toISOString().slice(0, 10) +
    ' (' +
    allRanked.length +
    ' new)',

  content: Buffer
    .from(JSON.stringify(db, null, 2))
    .toString('base64'),

  branch: 'state'
};

// IMPORTANT
if (sha) {
  payload.sha = sha;
}

return [{
  json: {
    github_payload: payload,
    sha_debug: sha,
    new_jobs: allRanked.length,
    total: merged.length,
    top5: allRanked.slice(0, 5)
  }
}];

const d = $input.first().json;
console.log('=== AGENT 1 COMPLETE ===');
console.log('New: ' + d.new_jobs + ' | Total DB: ' + d.total);
if (d.top5 && d.top5[0]) {
  const t = d.top5[0];
  console.log('Top: "' + t.title + '" @ ' + t.company +
    ' | Score:' + t.relevance_score + ' | ID:' + t.job_id);
}
return [{ json: { status: 'success', new_jobs: d.new_jobs,
  total: d.total, completed_at: new Date().toISOString() } }];

function makeId(title, company) {
  return 'j_' +
    (
      title.toLowerCase().replace(/[^a-z0-9]/g, '') +
      company.toLowerCase().replace(/[^a-z0-9]/g, '')
    ).slice(0, 16);
}

const now = new Date().toISOString();
const body = $input.first().json.body || '';

if (body.length < 100) {
  return [{ json: { _sentinel: true, source: 'internshala' } }];
}

const jobs = [];

const cardRegex = /<div[^>]*(?:internship_card|internship-listing-card|individual_internship)[^>]*>([\s\S]*?)<\/div>/gi;

let match;

while ((match = cardRegex.exec(body)) !== null) {
  const block = match[1];

  const title =
    (block.match(/profile-name[^>]*>([^<]+)/i)?.[1] ||
     block.match(/job-internship-name[^>]*>([^<]+)/i)?.[1] ||
     '').trim();

  const company =
    (block.match(/company-name[^>]*>([^<]+)/i)?.[1] || '').trim();

  const location =
    (block.match(/location-link[^>]*>([^<]+)/i)?.[1] ||
     block.match(/location[^>]*>([^<]+)/i)?.[1] ||
     'India').trim();

  const stipend =
    (block.match(/stipend[^>]*>([^<]+)/i)?.[1] ||
     block.match(/stipend-value[^>]*>([^<]+)/i)?.[1] ||
     '').trim() || null;

  const href =
    block.match(/href="([^"]*\/internship\/[^"]*)"/i)?.[1] || null;

  if (!title || !company) continue;

  const id = makeId(title, company);

  jobs.push({
    job_id: id,
    source: 'internshala',
    title,
    company,
    location,
    stipend,
    job_url: href
      ? (href.startsWith('http')
          ? href
          : 'https://internshala.com' + href)
      : null,
    job_type: 'internship',
    hash: id.slice(2),
    date_found: now,
    date_scraped: now,
    date_posted: now,
    description_text: '',
    skills_required: [],
    relevance_score: 0,
    status: 'new',
    tags: []
  });
}

if (!jobs.length) {
  return [{ json: { _sentinel: true, source: 'internshala' } }];
}

return jobs.map(j => ({ json: j }));
